import socket
import threading
import json
import time
import random
import os
from typing import Dict, List, Tuple, Any

HOST = os.environ.get("GAME_SERVER_HOST", "0.0.0.0")
PORT = int(os.environ.get("GAME_SERVER_PORT", "27015"))
BUFFER_SIZE = 65535
SERVER_NAME = os.environ.get("GAME_SERVER_NAME", "Example Game Server")
MAP_NAME = os.environ.get("GAME_SERVER_MAP", "arena_01")
GAMEMODE = os.environ.get("GAME_SERVER_MODE", "deathmatch")
MAX_PLAYERS = int(os.environ.get("GAME_SERVER_MAX_PLAYERS", "64"))
PASSWORD = os.environ.get("GAME_SERVER_PASSWORD", "0") == "1"
REGION = os.environ.get("GAME_SERVER_REGION", "global")
GAME_NAME = os.environ.get("GAME_NAME", "ExampleGame")
PROTOCOL_VERSION = int(os.environ.get("GAME_PROTOCOL_VERSION", "1"))

class GameState:
    def __init__(self) -> None:
        self.lock = threading.Lock()
        self.start_time = time.time()
        self.round_number = 1
        self.team_scores = {"red": 0, "blue": 0}
        self.players = self._generate_players(48)

    def _generate_players(self, count: int) -> List[Dict[str, Any]]:
        players = []
        for i in range(count):
            players.append({
                "id": i + 1,
                "name": f"Player_{i+1}",
                "score": random.randint(0, 250),
                "kills": random.randint(0, 100),
                "deaths": random.randint(0, 100),
                "ping": random.randint(20, 180),
                "team": random.choice(["red", "blue", "spectator"]),
                "bot": random.choice([False, False, False, True]),
                "connected_seconds": random.randint(30, 7200),
            })
        return players

    def snapshot(self) -> Dict[str, Any]:
        with self.lock:
            uptime = int(time.time() - self.start_time)
            current_players = [p for p in self.players if p["team"] != "spectator"]
            return {
                "server": {
                    "name": SERVER_NAME,
                    "game": GAME_NAME,
                    "map": MAP_NAME,
                    "mode": GAMEMODE,
                    "protocol_version": PROTOCOL_VERSION,
                    "region": REGION,
                    "password": PASSWORD,
                    "uptime_seconds": uptime,
                    "max_players": MAX_PLAYERS,
                    "num_players": len(current_players),
                    "num_bots": sum(1 for p in self.players if p["bot"]),
                },
                "game_state": {
                    "round_number": self.round_number,
                    "team_scores": dict(self.team_scores),
                    "time_limit_seconds": 1200,
                    "round_time_elapsed_seconds": uptime % 1200,
                    "match_state": "in_progress",
                },
                "players": list(self.players),
            }

    def simulate(self) -> None:
        while True:
            time.sleep(5)
            with self.lock:
                self.round_number += 1 if random.random() < 0.1 else 0
                self.team_scores["red"] += random.randint(0, 2)
                self.team_scores["blue"] += random.randint(0, 2)
                for p in self.players:
                    p["score"] += random.randint(0, 5)
                    p["kills"] += random.randint(0, 2)
                    p["deaths"] += random.randint(0, 2)
                    p["ping"] = max(5, min(300, p["ping"] + random.randint(-10, 10)))
                    p["connected_seconds"] += 5

class UDPGameServer:
    def __init__(self, host: str, port: int, game_state: GameState) -> None:
        self.host = host
        self.port = port
        self.game_state = game_state
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind((self.host, self.port))

    def serve_forever(self) -> None:
        while True:
            data, addr = self.sock.recvfrom(BUFFER_SIZE)
            threading.Thread(target=self.handle_packet, args=(data, addr), daemon=True).start()

    def handle_packet(self, data: bytes, addr: Tuple[str, int]) -> None:
        try:
            text = data.decode("utf-8", errors="ignore").strip()
            if text.lower() in ("status", "getstatus", "fullstatus", "query"):
                payload = self.build_status_response()
                self.send_large_response(payload, addr)
            elif text.lower() in ("ping", "info", "getinfo"):
                payload = json.dumps({
                    "type": "info",
                    "server": self.game_state.snapshot()["server"],
                }, separators=(",", ":")).encode("utf-8")
                self.sock.sendto(payload, addr)
            else:
                payload = json.dumps({
                    "type": "error",
                    "error": "unknown_query",
                    "accepted_queries": ["status", "getstatus", "fullstatus", "query", "ping", "info", "getinfo"]
                }, separators=(",", ":")).encode("utf-8")
                self.sock.sendto(payload, addr)
        except Exception as e:
            payload = json.dumps({
                "type": "error",
                "error": "server_exception",
                "detail": str(e),
            }, separators=(",", ":")).encode("utf-8")
            self.sock.sendto(payload, addr)

    def build_status_response(self) -> bytes:
        snapshot = self.game_state.snapshot()
        response = {
            "type": "status",
            "timestamp": int(time.time()),
            "data": snapshot,
        }
        return json.dumps(response, separators=(",", ":")).encode("utf-8")

    def send_large_response(self, payload: bytes, addr: Tuple[str, int]) -> None:
        max_chunk = 1200
        if len(payload) <= max_chunk:
            self.sock.sendto(payload, addr)
            return

        message_id = random.randint(1, 0x7FFFFFFF)
        total = (len(payload) + max_chunk - 1) // max_chunk

        for index in range(total):
            start = index * max_chunk
            end = start + max_chunk
            chunk = payload[start:end]
            packet = json.dumps({
                "type": "status_chunk",
                "message_id": message_id,
                "chunk_index": index,
                "chunk_count": total,
                "data": chunk.decode("utf-8", errors="ignore"),
            }, separators=(",", ":")).encode("utf-8")
            self.sock.sendto(packet, addr)

def main() -> None:
    game_state = GameState()
    threading.Thread(target=game_state.simulate, daemon=True).start()
    server = UDPGameServer(HOST, PORT, game_state)
    print(f"UDP game server listening on {HOST}:{PORT}")
    server.serve_forever()

if __name__ == "__main__":
    main()